def _json_safe_product_payload(value: object) -> object:
    if value is None or isinstance(value, (str, int, float, bool)):
        return value
    if isinstance(value, bytes):
        return f"<bytes:{len(value)}>"
    if isinstance(value, google_oauth_service.GoogleWorkspaceAttachment):
        return {
            "attachment_id": str(value.attachment_id or "").strip(),
            "filename": str(value.filename or "").strip(),
            "mime_type": str(value.mime_type or "").strip(),
            "part_id": str(value.part_id or "").strip(),
            "size_bytes": int(value.size_bytes or 0),
            "content_bytes_present": bool(value.content_bytes),
        }
    if isinstance(value, dict):
        return {str(key): _json_safe_product_payload(item) for key, item in value.items()}
    if isinstance(value, (list, tuple, set)):
        return [_json_safe_product_payload(item) for item in value]
    if hasattr(value, "__dict__"):
        return {str(key): _json_safe_product_payload(item) for key, item in dict(vars(value)).items()}
    return str(value)


def _property_search_platform_aliases() -> tuple[str, ...]:
    return tuple(property_platform_keys())


def _is_known_property_search_platform(platform: str) -> bool:
    return is_known_property_platform(platform)


def _normalize_property_search_platform_inputs(value: object) -> tuple[str, ...]:
    normalized: list[str] = []
    if isinstance(value, (list, tuple, set)):
        candidates = tuple(str(item or "").strip() for item in value)
    elif value is None:
        candidates = ()
    else:
        candidates = (str(value or "").strip(),)
    for raw in candidates:
        current = _normalize_property_search_platform(raw)
        if not current or current in normalized:
            continue
        if current != "all" and not _is_known_property_search_platform(current):
            continue
        normalized.append(current)
    if not normalized:
        return ()
    if any(item == "all" for item in normalized):
        return ("all",)
    return tuple(normalized)


def _property_search_platforms_with_family_toggles(
    selected_platforms: tuple[str, ...],
    preferences: dict[str, object] | None,
) -> tuple[str, ...]:
    normalized = list(_normalize_property_search_platform_inputs(selected_platforms))
    payload = dict(preferences or {})
    toggle_platforms = (
        ("include_broker_direct_sources", "broker_direct_at"),
        ("include_community_signals", "community_signals_at"),
        ("include_developer_project_signals", "developer_projects_at"),
        ("include_public_housing_signals", "public_housing_at"),
        ("include_distressed_sale_signals", "distressed_sales_at"),
    )
    for flag_name, platform_key in toggle_platforms:
        if bool(payload.get(flag_name)) and platform_key not in normalized:
            normalized.append(platform_key)
    return tuple(normalized)


def _property_search_pref_value_missing(value: object) -> bool:
    if value is None:
        return True
    if isinstance(value, str):
        return not value.strip()
    if isinstance(value, (list, tuple, set, dict)):
        return len(value) == 0
    return False


def _property_search_match_score_cap(preferences: dict[str, object] | None) -> int:
    try:
        snapshot = property_commercial_snapshot(preferences)
        return max(1, min(100, int(snapshot.get("max_match_score") or 45)))
    except Exception:
        return 45


def _property_search_effective_min_match_score(preferences: dict[str, object] | None) -> float:
    cap = _property_search_match_score_cap(preferences)
    default_score = min(_PROPERTY_SEARCH_DEFAULT_HIGH_MATCH_MIN_SCORE, float(cap))
    try:
        requested_score = float(str(dict(preferences or {}).get("min_match_score") or "").strip())
    except Exception:
        requested_score = 0.0
    if requested_score <= 0.0:
        requested_score = default_score
    return float(max(1.0, min(requested_score, float(cap))))


def _property_search_run_expired(at_iso: str, *, ttl_seconds: int = _PROPERTY_SEARCH_RUN_TTL_SECONDS) -> bool:
    parsed = _parse_utcish(at_iso)
    if parsed is None:
        return True
    return (datetime.now(timezone.utc) - parsed).total_seconds() > float(ttl_seconds)


def _property_search_run_stale_seconds() -> int:
    raw_value = str(os.getenv("EA_PROPERTY_SEARCH_RUN_STALE_SECONDS") or "").strip()
    if not raw_value:
        return _PROPERTY_SEARCH_RUN_STALE_DEFAULT_SECONDS
    try:
        parsed = int(raw_value)
    except Exception:
        return _PROPERTY_SEARCH_RUN_STALE_DEFAULT_SECONDS
    return max(60, min(parsed, 24 * 60 * 60))


def _property_search_run_is_stale(state: dict[str, object]) -> bool:
    status = str(state.get("status") or "").strip().lower()
    if not status or status in _PROPERTY_SEARCH_TERMINAL_STATUSES or status == "initialization_required":
        return False
    parsed = _parse_utcish(str(state.get("updated_at") or state.get("created_at") or ""))
    if parsed is None:
        return True
    return (datetime.now(timezone.utc) - parsed).total_seconds() > float(_property_search_run_stale_seconds())


