def _now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _parse_iso(value: str | None) -> datetime | None:
    normalized = str(value or "").strip()
    if not normalized:
        return None
    try:
        return datetime.fromisoformat(normalized.replace("Z", "+00:00"))
    except ValueError:
        return None


def _parse_utcish(value: str | None) -> datetime | None:
    parsed = _parse_iso(value)
    if parsed is None:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _float_or_none(value: object) -> float | None:
    if value in (None, ""):
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def _google_coordinate(value: object) -> float | None:
    candidate = _float_or_none(value)
    if candidate is None:
        return None
    if abs(candidate) > 180.0:
        candidate = candidate / 10000000.0
    return candidate


def _google_timestamp(value: object) -> str:
    if isinstance(value, (int, float)):
        return datetime.fromtimestamp(float(value) / 1000.0, tz=timezone.utc).isoformat()
    normalized = str(value or "").strip()
    if not normalized:
        return ""
    if normalized.isdigit():
        return datetime.fromtimestamp(int(normalized) / 1000.0, tz=timezone.utc).isoformat()
    parsed = _parse_utcish(normalized)
    return parsed.isoformat() if parsed is not None else ""


def _google_location_query_tokens(text: str) -> tuple[str, ...]:
    return tuple(token for token in re.findall(r"[0-9A-Za-zÄÖÜäöüß]+", str(text or "").lower()) if token)


def _google_location_duration_seconds(*, start_at: str, end_at: str) -> float:
    start = _parse_utcish(start_at)
    end = _parse_utcish(end_at)
    if start is None or end is None:
        return 0.0
    return max(0.0, (end - start).total_seconds())


def _google_location_history_auto_import_path() -> str:
    return str(os.getenv("EA_GOOGLE_LOCATION_HISTORY_PATH") or "").strip()


def _google_location_history_match_max_gap_seconds() -> float:
    configured = _float_or_none(os.getenv("EA_GOOGLE_LOCATION_MATCH_MAX_GAP_SECONDS"))
    return max(0.0, configured if configured is not None else 6 * 3600.0)


def _google_location_history_export_window_days() -> int:
    configured = os.getenv("EA_GOOGLE_LOCATION_HISTORY_EXPORT_WINDOW_DAYS")
    try:
        return max(1, min(int(configured or "30"), 365))
    except ValueError:
        return 30


def _google_location_history_sync_cooldown_seconds() -> int:
    configured = os.getenv("EA_GOOGLE_LOCATION_HISTORY_SYNC_COOLDOWN_SECONDS")
    try:
        return max(300, min(int(configured or "21600"), 7 * 24 * 3600))
    except ValueError:
        return 21600


def _google_location_history_window_payloads(payload: object, *, source_path: str) -> list[dict[str, object]]:
    source_label = Path(source_path).name or "google-location-history"
    rows: list[dict[str, object]] = []

    def _append_window(
        *,
        source_type: str,
        start_at: object,
        end_at: object,
        latitude: object,
        longitude: object,
        name: object = "",
        address: object = "",
        activity_type: object = "",
    ) -> None:
        start_value = _google_timestamp(start_at)
        end_value = _google_timestamp(end_at) or start_value
        lat_value = _google_coordinate(latitude)
        lon_value = _google_coordinate(longitude)
        if not start_value and not end_value:
            return
        if lat_value is None or lon_value is None:
            return
        rows.append(
            {
                "source_format": source_label,
                "source_type": str(source_type or "").strip() or "point",
                "location_name": compact_text(str(name or "").strip(), fallback="", limit=200),
                "location_address": compact_text(str(address or "").strip(), fallback="", limit=260),
                "location_latitude": lat_value,
                "location_longitude": lon_value,
                "location_start_at": start_value,
                "location_end_at": end_value,
                "location_duration_seconds": _google_location_duration_seconds(start_at=start_value, end_at=end_value),
                "activity_type": compact_text(str(activity_type or "").strip(), fallback="", limit=80),
            }
        )

    def _extract_map_coordinates(*, text: object = "", url: object = "") -> tuple[float | None, float | None]:
        candidates = [str(url or "").strip(), str(text or "").strip()]
        for candidate in candidates:
            if not candidate:
                continue
            parsed = urllib.parse.urlparse(candidate)
            query = urllib.parse.parse_qs(parsed.query)
            center = ""
            if query.get("center"):
                center = str(query.get("center", [""])[0] or "").strip()
            if center:
                try:
                    lat_text, lon_text = [part.strip() for part in center.split(",", 1)]
                    return float(lat_text), float(lon_text)
                except Exception:
                    pass
            match = re.search(r"@(-?\d+(?:\.\d+)?),(-?\d+(?:\.\d+)?)", candidate)
            if match:
                try:
                    return float(match.group(1)), float(match.group(2))
                except ValueError:
                    pass
        return None, None

    def _normalize_my_activity_title(title: object) -> tuple[str, str]:
        raw_title = compact_text(str(title or "").strip(), fallback="", limit=260)
        if not raw_title:
            return "", ""
        lowered = raw_title.lower()
        for prefix in ("directions to ", "searched for "):
            if lowered.startswith(prefix):
                remainder = raw_title[len(prefix):].strip()
                if "," in remainder:
                    location_name, _, location_address = remainder.partition(",")
                    return location_name.strip(), remainder.strip()
                return remainder, remainder
        return raw_title, raw_title

    def _from_my_activity_entry(entry: dict[str, object]) -> None:
        if str(entry.get("header") or "").strip().lower() != "maps":
            return
        timestamp = entry.get("time") or entry.get("timeStamp") or entry.get("timestamp")
        if not timestamp:
            return
        location_infos = [dict(item) for item in list(entry.get("locationInfos") or []) if isinstance(item, dict)]
        title = str(entry.get("title") or "").strip()
        title_url = str(entry.get("titleUrl") or "").strip()
        description = compact_text(str(entry.get("description") or "").strip(), fallback="", limit=260)
        default_name, default_address = _normalize_my_activity_title(title)
        if description.lower().startswith("current location"):
            lines = [line.strip() for line in description.splitlines() if line.strip()]
            if len(lines) >= 2:
                default_address = compact_text(lines[-1], fallback=default_address, limit=260)
        if not location_infos:
            lat_value, lon_value = _extract_map_coordinates(text=description or title, url=title_url)
            if lat_value is None or lon_value is None:
                return
            _append_window(
                source_type="maps_my_activity",
                start_at=timestamp,
                end_at=timestamp,
                latitude=lat_value,
                longitude=lon_value,
                name=default_name,
                address=default_address,
                activity_type=entry.get("header") or "Maps",
            )
            return
        for info in location_infos:
            lat_value, lon_value = _extract_map_coordinates(text=info.get("url") or description, url=title_url)
            if lat_value is None or lon_value is None:
                continue
            _append_window(
                source_type="maps_my_activity",
                start_at=timestamp,
                end_at=timestamp,
                latitude=lat_value,
                longitude=lon_value,
                name=default_name or info.get("name") or title,
                address=default_address or info.get("name") or description,
                activity_type=info.get("source") or entry.get("header") or "Maps",
            )

    def _from_place_visit(place_visit: dict[str, object]) -> None:
        location = dict(place_visit.get("location") or {})
        duration = dict(place_visit.get("duration") or {})
        _append_window(
            source_type="place_visit",
            start_at=duration.get("startTimestamp") or duration.get("startTimestampMs") or place_visit.get("startTime"),
            end_at=duration.get("endTimestamp") or duration.get("endTimestampMs") or place_visit.get("endTime"),
            latitude=location.get("latitudeE7") or location.get("latitude"),
            longitude=location.get("longitudeE7") or location.get("longitude"),
            name=location.get("name") or location.get("placeName") or location.get("address"),
            address=location.get("address") or location.get("semanticType"),
            activity_type=place_visit.get("visitConfidence"),
        )

    def _from_activity_segment(segment: dict[str, object]) -> None:
        start_location = dict(segment.get("startLocation") or {})
        end_location = dict(segment.get("endLocation") or {})
        latitude = start_location.get("latitudeE7") or start_location.get("latitude")
        longitude = start_location.get("longitudeE7") or start_location.get("longitude")
        if latitude in (None, ""):
            latitude = end_location.get("latitudeE7") or end_location.get("latitude")
        if longitude in (None, ""):
            longitude = end_location.get("longitudeE7") or end_location.get("longitude")
        _append_window(
            source_type="activity_segment",
            start_at=segment.get("startTime") or segment.get("durationStartTimestamp"),
            end_at=segment.get("endTime") or segment.get("durationEndTimestamp"),
            latitude=latitude,
            longitude=longitude,
            name=segment.get("activityType") or segment.get("transitPath"),
            address=segment.get("distance"),
            activity_type=segment.get("activityType"),
        )

    def _from_point(entry: dict[str, object]) -> None:
        _append_window(
            source_type="point",
            start_at=entry.get("timestamp") or entry.get("timestampMs") or entry.get("time"),
            end_at=entry.get("timestamp") or entry.get("timestampMs") or entry.get("time"),
            latitude=entry.get("latitudeE7") or entry.get("latitude"),
            longitude=entry.get("longitudeE7") or entry.get("longitude"),
            name=entry.get("name") or entry.get("address"),
            address=entry.get("address"),
        )

    def _walk(node: object) -> None:
        if isinstance(node, dict):
            if isinstance(node.get("placeVisit"), dict):
                _from_place_visit(dict(node.get("placeVisit") or {}))
            elif isinstance(node.get("activitySegment"), dict):
                _from_activity_segment(dict(node.get("activitySegment") or {}))
            elif any(key in node for key in ("latitudeE7", "latitude", "longitudeE7", "longitude")):
                _from_point(node)
            elif str(node.get("header") or "").strip().lower() == "maps":
                _from_my_activity_entry(node)
            for key in ("timelineObjects", "locations", "semanticSegments", "records", "data"):
                child = node.get(key)
                if isinstance(child, list):
                    for item in child:
                        _walk(item)
        elif isinstance(node, list):
            for item in node:
                _walk(item)

    _walk(payload)
    return rows


def _google_location_match_projection(match: dict[str, object] | None) -> dict[str, object]:
    payload = dict(match or {})
    return {
        "location_match_status": str(payload.get("location_match_status") or "").strip(),
        "location_match_reason": str(payload.get("location_match_reason") or "").strip(),
        "location_name": str(payload.get("location_name") or "").strip(),
        "location_address": str(payload.get("location_address") or "").strip(),
        "location_latitude": _float_or_none(payload.get("location_latitude")),
        "location_longitude": _float_or_none(payload.get("location_longitude")),
        "location_start_at": str(payload.get("location_start_at") or "").strip(),
        "location_end_at": str(payload.get("location_end_at") or "").strip(),
        "location_source": str(payload.get("location_source") or "").strip(),
        "location_confidence": float(payload.get("location_confidence") or 0.0),
    }


def _is_past_due(value: str | None) -> bool:
    when = _parse_iso(value)
    if when is None:
        return False
    return when <= datetime.now(timezone.utc)


def _hours_since(value: str | None) -> int:
    when = _parse_iso(value)
    if when is None:
        return 0
    return max(int((datetime.now(timezone.utc) - when).total_seconds() // 3600), 0)


def _memo_issue_reason(*, reason: str = "", error: str = "") -> str:
    normalized_error = str(error or "").strip()
    normalized_reason = str(reason or "").strip().lower()
    if normalized_error:
        if "domain not verified" in normalized_error.lower():
            return "Domain not verified"
        detail = normalized_error
        if normalized_error.startswith("registration_email_send_failed:"):
            detail = normalized_error.split(":", 2)[-1]
        if detail.startswith("{") and detail.endswith("}"):
            try:
                parsed = json.loads(detail)
            except Exception:
                parsed = {}
            extracted = str(parsed.get("error") or "").strip()
            if extracted:
                return extracted
        return compact_text(normalized_error, fallback="Memo delivery failed.", limit=160)
    if normalized_reason == "quiet_hours":
        return "Blocked by quiet hours"
    if normalized_reason == "recipient_missing":
        return "Recipient email missing"
    if normalized_reason == "email_delivery_not_configured":
        return "Email delivery is not configured"
    if normalized_reason == "unsupported_delivery_channel":
        return "Delivery channel is unsupported"
    if normalized_reason == "digest_not_available":
        return "Memo digest was not available"
    return compact_text(normalized_reason.replace("_", " "), fallback="", limit=160)


def _memo_issue_fix(*, reason: str = "", error: str = "") -> tuple[str, str]:
    normalized_reason = str(reason or "").strip().lower()
    normalized_error = str(error or "").strip().lower()
    if "google_" in normalized_reason or "google_" in normalized_error:
        return "/app/settings/google", "Open Google settings"
    if "domain not verified" in normalized_error or normalized_reason in {"email_delivery_not_configured", "unsupported_delivery_channel"}:
        return "/app/settings/support", "Open support"
    if normalized_reason in {"recipient_missing", "quiet_hours"}:
        return "/app/settings", "Open memo settings"
    return "/app/settings/outcomes", "Open outcomes"


def _memo_issue_fix_detail(*, reason: str = "", error: str = "") -> str:
    normalized_reason = str(reason or "").strip().lower()
    normalized_error = str(error or "").strip().lower()
    if "google_" in normalized_reason or "google_" in normalized_error:
        return "Reconnect Google before the next sync or approved send."
    if "domain not verified" in normalized_error:
        return "Verify the sending domain in the email provider before the next memo cycle."
    if normalized_reason == "email_delivery_not_configured":
        return "Configure outbound email delivery before the next memo cycle."
    if normalized_reason == "unsupported_delivery_channel":
        return "Use a supported delivery channel for memo email delivery."
    if normalized_reason == "recipient_missing":
        return "Set the memo recipient in morning memo settings."
    if normalized_reason == "quiet_hours":
        return "Adjust quiet hours or wait for the allowed delivery window."
    if normalized_reason == "digest_not_available":
        return "Regenerate the memo after the workspace loop refreshes."
    return ""


def _workspace_access_email_text(
    *,
    workspace_name: str,
    access_url: str,
    role: str,
    display_name: str = "",
    expires_at: str = "",
) -> str:
    minutes = _minutes_until(expires_at_iso=expires_at)
    role_label = str(role or "principal").strip().replace("_", " ").title() or "Principal"
    workspace_label = str(workspace_name or "Executive Assistant workspace").strip() or "Executive Assistant workspace"
    display = str(display_name or "").strip()
    body = [
        "Hello,",
        "",
        f"Open this secure link to return to {workspace_label}:",
        "",
        access_url,
        "",
        f"This link expires in about {minutes} minutes.",
    ]
    if display:
        body.extend(["", f"This link opens your {role_label.lower()} access as {display}."])
    else:
        body.extend(["", f"This link opens your {role_label.lower()} access to the workspace."])
    body.extend(
        [
            "",
            "Google is connected later as a workspace data source. It is not your app login.",
        ]
    )
    return "\n".join(body).strip() + "\n"


